package com.JavaOperator;

public class RelationalOperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
	int x = 10;
	int y = 20;
	
	boolean result = x == y;
	System.out.println("x == y? " +result);
	result =  x != y;
	
	System.out.println("x != y? " +result);
	result =  x > y;
	
	System.out.println("x > y? " +result);
	result =  x >= y;
	
	System.out.println("x >= y? " +result);
	result =  x < y;
	
	System.out.println("x < y? " +result);
	result =  x == y;

	}

}
